&quot;; } }else { for(int i = 0;i &lt; activity[u].size(); i++) dfs( activity[u][i]); } tempp.pop_back(); } int main(){ fill(edge[0], edge[0] + mss * mss, INF); int u, v, w; cin &gt;&gt; n &gt;&gt; m; for(int i = 0;i &lt; m;i++){ cin &gt;&gt; u &gt;&gt; v &gt;&gt; w; edge[u][v] = w; ingree[v]++; } if(!topu()){ cout &lt;&lt; &quot;NO
&quot;; return 0; } cout &lt;&lt; &quot;YES
&quot;; critical_path(); int q; cin &gt;&gt; q; for(int i = 0;i &lt; q;i++){ cin &gt;&gt; u &gt;&gt; v; cout &lt;&lt; e[u][v] &lt;&lt; ' ' &lt;&lt; l[u][v] &lt;&lt; endl; } cout &lt;&lt; maxtime &lt;&lt; endl; for(int i = 1;i &lt;= n;i++) if( activity[i].size() &amp;&amp; ve[i] == 0) dfs(i); //一个关键路径的起点的后序存在节点的 且最早开始时间为0 }

