&quot;); } const int maxn = 100; int merge(int arr[], int l1, int r1, int l2, int r2){ int i = l1, j = l2, k = 0; int temp[maxn]; while(i &lt;= r1 &amp;&amp; j &lt;= r2){ if(arr[i] &lt; arr[j]) temp[k++] = arr[i++]; else if(arr[i] &gt;= arr[j]) temp[k++] = arr[j++]; } while(i &lt;= r1) temp[k++] = arr[i++]; while(j &lt;= r2) temp[k++] = arr[j++]; for(int i = l1, k = 0; i &lt;= r2; i++, k++) arr[i] = temp[k]; } //递归写法 int mergeSort_re(int A[], int l, int r){ if(l &lt; r){ int mid = (l + r) / 2; mergeSort_re(A, l, mid); mergeSort_re(A, mid + 1, r); merge(A, l, mid, mid + 1, r); } } // 迭代写法 int mergeSort_for(int A[], int l, int r){ if(l &lt; r){ int n = r - l + 1; //step为组内元素个数 for(int step = 1; step &lt;= n; step *= 2){ for(int i = 0; i &lt; n; i += 2*step){ //这么写行不行？测试一下A[5] // 事实证明这种写法很优美! merge(&amp;A[l], i, i + step - 1, i + step, min(i + 2 * step - 1, n - 1)); } printArr(A, l, r); } } } int main(){ // freopen(&quot;./data.in&quot;, &quot;r&quot;, stdin); int c[10] = {5, 3, 2, 1, 7, 2, 10, 3, 5, -1}, n = 10; // mergeSort_re(c, 0, n - 1); mergeSort_for(c, 5, n - 1); printArr(c, 0, n - 1); return 0; } 快速排序不稳定，复杂度为O(nlgn)O(nlgn)到O(n2)O(n2)，最广泛使用的排序算法。 //挖沙法 分割 int Partition(int A[], int l, int r){ //三个数取最小值 int minp = l; if(A[r] &lt; A[minp]) minp = r; if(A[(r + l) / 2] &lt; A[minp]) minp = (r + l) / 2; int temp = A[minp]; A[minp] = A[l]; A[l] = temp; int i = l, j = r; while(i &lt; j){ while(i &lt; j &amp;&amp; temp &lt; A[j]) j--; A[i] = A[j]; while(i &lt; j &amp;&amp; temp &gt;= A[i]) i++; A[j] = A[i]; } A[j] = temp; return j; } void quickSort(int A[], int l, int r){ if(l &gt;= r) return; int mid = partition(A, l, r); printArr(A, 0, 9); printf(&quot;%d
&quot;, mid); quickSort(A, l, mid - 1); // 如果这里取mid - 1, 可能会导致mid为右侧最小值的情况时，无限partition！（没错，微妙的递归） quickSort(A, mid + 1, r); }

