 3][j / 3]) &amp; 0x1FF; if( !(mask &amp; (mask - 1))){ int digitnum = __builtin_ctz(mask &amp; (-mask)) ; flip(i, j, digitnum); board[i][j] = digitnum + '0' + 1; flag = true; } } } } for (int i = 0; i &lt; 9; ++i) { for (int j = 0; j &lt; 9; ++j) { if (board[i][j] == '.') { spaces.emplace_back(i, j); } } } dfs(board, 0); } };

