&quot;); } 中午时间不要打代码，太困了 437. Path Sum III 路径之和类似，但不相同。 前缀和 + 递归 /** * Definition for a binary tree node. * struct TreeNode { * int val; * TreeNode *left; * TreeNode *right; * TreeNode() : val(0), left(nullptr), right(nullptr) {} * TreeNode(int x) : val(x), left(nullptr), right(nullptr) {} * TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {} * }; */ class Solution { public: int count = 0; int pathSum(TreeNode* root, int sum) { add(root, 0); findNode(root, sum, 0); return count; } void findNode(TreeNode* root, int num, int presum){ if(!root) return; cal(root, num, presum); findNode(root-&gt;left, num, root-&gt;val); findNode(root-&gt;right, num, root-&gt;val); } void cal(TreeNode* root, int target, int presum){ if(!root) return; if(root-&gt;val - presum == target) count++; cal(root-&gt;left, target, presum); cal(root-&gt;right, target, presum); } void add(TreeNode* root, int presum){ if(!root) return; root-&gt;val += presum; add(root-&gt;left, root-&gt;val); add(root-&gt;right, root-&gt;val); } }; 写法二：提供一种递归的小小思路 class Solution { public: int count = 0; int pathSum(TreeNode* root, int sum) { if(!root) return 0; return cal(root, sum) + pathSum(root-&gt;left, sum) + pathSum(root-&gt;right, sum); } int cal(TreeNode* root, int sum){ if(!root) return 0; sum -= root-&gt;val; return (sum == 0) + cal(root-&gt;left, sum) + cal(root-&gt;right, sum); } }; 最优解法：前缀和 + 回溯 + 维护前缀和出现的次数：times[presum] 突然想到3数之和。 /** * Definition for a binary tree node. * struct TreeNode { * int val; * TreeNode *left; * TreeNode *right; * TreeNode() : val(0), left(nullptr), right(nullptr) {} * TreeNode(int x) : val(x), left(nullptr), right(nullptr) {} * TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {} * }; */ class Solution { public: unordered_map&lt;int, int&gt; ct = {{0,1}}; int pathSum(TreeNode* root, int sum) { int amount = 0; dfs(root, 0, sum, amount); return amount; } void dfs(TreeNode *root, int presum, int sum, int &amp;amount){ if(!root) return; root-&gt;val += presum; amount += ct[root-&gt;val - sum]; ++ct[root-&gt;val]; dfs(root-&gt;left, root-&gt;val, sum, amount); dfs(root-&gt;right, root-&gt;val, sum, amount); --ct[root-&gt;val]; } }; 面36：把二叉搜索树转化为双向链表（同链表中的内容）题面：如题，要求不创建任何新节点，只能调整树中节点的指向。输出调整后的排序链表。 思路：可以从递归的角度入手。对于一个节点A，中序遍历到A，则A的左子树已经转化为了链表，连接好A和A的左子树的最大节点（前一个指针）的指针则连接完成。 那对于A的右子树的最小节点B与A之间的连接，也可以看成B与前一个节点的指针相互链接。那么我们只需要在中序遍历的过程中改变前一个指针的内容即可。 注意一下整棵树的最大的右指针和最小节点的左指针，发现都应该是空，无需额外修改。 对于一个节点A的左右指针，分别指向按顺序排列的旁边两个节点。可以用中序遍历来获取该节点的前一个节点B的指针，并设置好B的右指针和A的左指针。如此就可以在中序遍历的后设置除了最后一个节点的右指针，但是右指针本来就应该是NULL，所以无需修改。 代码：void AdjustLinkCore(BinaryTreeNode* pRoot, BinaryTreeNode *&amp;preNode, BinaryTreeNode *&amp;pHead){ if(pRoot == nullptr) return; AdjustLinkCore(pRoot-&gt;pLeft, preNode, pHead); if(pHead == nullptr) pHead = pRoot; pRoot-&gt;pLeft = preNode; if(preNode) preNode-&gt;pRight = pRoot; preNode = pRoot; AdjustLinkCore(pRoot-&gt;pRight, preNode, pHead); } BinaryTreeNode* AdjustLink(BinaryTreeNode* pRoot){ BinaryTreeNode *preNode = nullptr; BinaryTreeNode *pHead = nullptr; AdjustLinkCore(pRoot, preNode, pHead); return pHead; } 面36：序列化和反序列化二叉树题面：序列化定义： 序列化 (Serialization)是将对象的状态信息转换为可以存储或传输的形式的过程。在序列化期间，对象将其当前状态写入到临时或持久性存储区。以后，可以通过从存储区中读取或反序列化对象的状态，重新创建该对象。 二叉树的序列化可以把非空节点的值序列化，把空节点序列化为$。 思路：由于序列化把空节点的信息也包含进来了，所以无需添加更多序列。 这题更像流的应用题 代码：void Serialize(BinaryTreeNode *pRoot, ostream&amp; stream){ if(pRoot == nullptr){ stream &lt;&lt; '$'; return; } stream &lt;&lt; pRoot-&gt;value &lt;&lt; ','; Serialize(pRoot-&gt;pLeft); Serialize(pRoot-&gt;pRight); } void Deserialize(BinaryTreeNode *&amp;pRoot, istream&amp; stream){ int number; if(ReadSteam(stream, &amp;number)){ pRoot = new BinaryTreeNode(); pNew-&gt;pLeft = nullptr; pNew-&gt;pRight = nullptr; pNew-&gt;value = number; } Deserialize(pRoot-&gt;pLeft, stream); Deserialize(pRoot-&gt;pRight, steam); }
